SELECT agg.result_type AS resultType, agg.display_name AS displayName, agg.table_name AS tableName, agg.user_id AS userId, agg.source_type AS sourceType, agg.source_session_id AS sourceSessionId, agg.source_result_id AS sourceResultId, agg.status AS status, agg.score AS score, agg.analysis_summary AS analysisSummary, agg.detail_ref AS detailRef, agg.source_time AS sourceTime, agg.version_no AS versionNo, agg.note AS note FROM (
) agg
ORDER BY agg.source_time DESC, agg.record_id DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT agg.result_type AS resultType, MAX(agg.display_name) AS displayName, agg.table_name AS tableName, MAX(agg.source_type) AS sourceType, MAX(agg.note) AS note FROM (
) agg
GROUP BY agg.result_type, agg.table_name ORDER BY agg.result_type ASC

