UPDATE xm_quiz_result SET source_type = #{record.sourceType}, source_session_id = #{record.sourceSessionId}, source_task_id = #{record.sourceTaskId}, source_result_id = #{record.sourceResultId}, question_total = #{record.questionTotal}, correct_total = #{record.correctTotal}, status = #{record.status}, score = #{record.score}, analysis_summary = #{record.analysisSummary}, detail_ref = #{record.detailRef},
question_items_json = #{record.questionItemsJson},
source_time = #{record.occurredAt}, version_no = #{record.versionNo}, update_time = #{record.updatedAt}, remark = #{record.note} WHERE quiz_result_id = #{record.generatedId}

UPDATE xm_learning_record
SET source_result_id = #{sourceResultId}
WHERE record_id = #{recordId}
